parameters.jsonBody:
={
  "model": "gpt-4o-mini",
  "messages": [
    {
      "role": "system",
      "content": "Eres un experto en productos deportivos. Del texto que te doy, extrae la información del producto. Responde SOLO con JSON válido, sin markdown ni explicaciones.\n\nCampos a extraer:\n- productType: tipo de producto en singular y castellano. Valores válidos: Zapatilla, Chancla, Bota, Sandalia, Zueco, Camiseta, Sudadera, Chaqueta, Pantalón, Malla, Chándal, Conjunto, Polo, Chaleco, Bañador, Bikini, Body, Mono, Vestido, Falda, Calcetín, Camisa, Top, Cortavientos, Chubasquero, Mochila, Bolsa, Gorra, Gorro, Guante, Gafa, Reloj, Bufanda, Balón, Raqueta, Pala, Protección, Rodillera, Espinillera, Codera, Casco, Esterilla, Pesa, Bicicleta, Neopreno, Culotte, Producto.\n- model: nombre del modelo (sin marca, sin tipo, sin color, sin talla, sin género, sin año). Solo las palabras que identifican el modelo específico.\n- color: color principal detectado, en castellano, primera letra mayúscula.\n\nSi no puedes determinar algún campo, usa cadena vacía."
    },
    {
      "role": "user",
      "content": {{ JSON.stringify('Marca: ' + ($json.body.brand || '?') + '. Texto completo: ' + ($json.body.name || '')) }}
    }
  ],
  "temperature": 0,
  "max_tokens": 150,
  "response_format": { "type": "json_object" }
}

parameters.jsCode:
const input = $input.first().json;
let result = { productType: '', model: '', color: '' };
try {
  const content = input.choices[0].message.content;
  result = JSON.parse(content);
} catch(e) {}
return [{ json: result }];

